  ('elementary-e0adf6cd-moex-00518', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-112-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '在大學採用協同教學時，下列何位教授的論述較不適切？', '["甲教授-跨科的教學團隊可能在溝通內容或方法時出現緊張", "乙教授-教師們會關心教學負荷和薪水可能受到的影響", "丙教授-協同教學可以同時提升教和學兩方面的品質", "丁教授-協同教學只適用於大學的大班級或團體"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:39+00:00", "source_pdf_sha1": "3d96b660454f", "answer_pdf_sha1": "46381198e246", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL)
